acceptance_tests.test_meter.py:
import meter

def test_pricing_exists():
    assert 'gpt-4' in meter.PRICING
    assert 'input' in meter.PRICING['gpt-4'] and 'output' in meter.PRICING['gpt-4']

def test_cost_basic():
    meter.PRICING['test-model'] = {'input': 1.0, 'output': 2.0}
    c = meter.cost('test-model', {'input_tokens': 1000, 'output_tokens': 1000})
    assert abs(c - 3.0) < 1e-6

def test_cost_unknown_model_raises():
    try:
        meter.cost('nonexistent-model-xyz', {'input_tokens': 10, 'output_tokens': 10})
        assert False, 'expected KeyError'
    except KeyError:
        pass

def test_report_per_agent_and_total():
    meter.PRICING['test-model'] = {'input': 1.0, 'output': 2.0}
    records = [
        {'agent': 'A', 'model': 'test-model', 'input_tokens': 1000, 'output_tokens': 0},
        {'agent': 'A', 'model': 'test-model', 'input_tokens': 1000, 'output_tokens': 0},
        {'agent': 'B', 'model': 'test-model', 'input_tokens': 0, 'output_tokens': 1000},
    ]
    r = meter.report(records)
    assert abs(r['per_agent']['A'] - 2.0) < 1e-6
    assert abs(r['per_agent']['B'] - 2.0) < 1e-6
    assert abs(r['total'] - 4.0) < 1e-6

acceptance_tests.test_ingest.py:
import ingest

def test_parse_jsonl_basic():
    text = '{"a": 1}\n{"b": 2}\n\n{"c": 3}\n'
    recs = ingest.parse_jsonl(text)
    assert recs == [{'a': 1}, {'b': 2}, {'c': 3}]

def test_validate_record_true():
    rec = {'agent': 'x', 'model': 'gpt-4', 'input_tokens': 5, 'output_tokens': 10}
    assert ingest.validate_record(rec) is True

def test_validate_record_false_missing_key():
    rec = {'agent': 'x', 'model': 'gpt-4', 'input_tokens': 5}
    assert ingest.validate_record(rec) is False

def test_validate_record_false_bad_type():
    rec = {'agent': 'x', 'model': 'gpt-4', 'input_tokens': 'five', 'output_tokens': 10}
    assert ingest.validate_record(rec) is False

def test_validate_record_no_raise_on_garbage():
    assert ingest.validate_record({}) is False
    assert ingest.validate_record({'random': 1}) is False

def test_load_usage_filters_invalid():
    text = '{"agent":"a","model":"gpt-4","input_tokens":1,"output_tokens":2}\n{"agent":"b"}\n'
    out = ingest.load_usage(text)
    assert len(out) == 1
    assert out[0]['agent'] == 'a'

