files.meter.py:
DEFAULT_RATES = {
    'gpt-4o': {'in': 0.005, 'out': 0.015},
    'gpt-4o-mini': {'in': 0.00015, 'out': 0.0006},
}

DEFAULT_RATE = {'in': 0.001, 'out': 0.002}


def _rate_for(model):
    return DEFAULT_RATES.get(model, DEFAULT_RATE)


def cost(model, usage):
    rate = _rate_for(model)
    tokens_in = usage.get('tokens_in', 0)
    tokens_out = usage.get('tokens_out', 0)
    cost_in = (tokens_in / 1000.0) * rate['in']
    cost_out = (tokens_out / 1000.0) * rate['out']
    return cost_in + cost_out


def aggregate(records):
    per_agent = {}
    per_model = {}
    total = 0.0
    for r in records:
        agent = r.get('agent')
        model = r.get('model')
        c = cost(model, r)
        per_agent[agent] = per_agent.get(agent, 0.0) + c
        per_model[model] = per_model.get(model, 0.0) + c
        total += c
    return {'per_agent': per_agent, 'per_model': per_model, 'total': total}

